{
  "domain_analysis": {
    "business_context": "Order cancellation is a core lifecycle operation in logistics and courier systems. It allows a customer (shipper or end-consumer) to revoke a previously placed order before the courier network has irreversibly committed resources. Cancellation has cascading effects on dispatch, driver assignment, inventory holds, billing, and SLA tracking.",
    "bounded_context": "Order Management",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request for courier/logistics service that progresses through a defined lifecycle: placed → confirmed → assigned → picked_up → in_transit → delivered (or cancelled)." },
      { "term": "Cancellation", "definition": "A user-initiated action that terminates an active order, halting further fulfillment and triggering compensating actions (refund, driver unassignment, inventory release)." },
      { "term": "Order Status", "definition": "The current lifecycle phase of an order. Determines which transitions — including cancellation — are permitted." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted without penalty or with reduced penalty." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after resources have been committed (e.g., driver assigned, pickup completed)." },
      { "term": "Compensating Action", "definition": "A downstream effect triggered by cancellation — e.g., refund issuance, driver notification, route re-optimization, inventory release." },
      { "term": "Refund", "definition": "The return of payment to the customer, full or partial, depending on the cancellation point in the order lifecycle." },
      { "term": "Initiator", "definition": "The actor requesting cancellation. May be the customer, an internal operator, or an automated system rule." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled if its current status is within the set of cancellable statuses (placed, confirmed, assigned). Orders that have been picked_up, are in_transit, or delivered cannot be cancelled — they must follow a return or dispute flow instead.",
      "invariant": true,
      "invariant_justification": "Once physical possession of goods has transferred (picked_up), cancellation is no longer a logically coherent operation — you cannot 'un-pick-up' a package. Allowing it would corrupt fulfillment state and create phantom shipments.",
      "testable_assertion": "Given an order with status in {picked_up, in_transit, delivered}, when a cancellation request is submitted, then the system MUST reject it with a clear error indicating the order is past the cancellable stage."
    },
    {
      "id": "BR-2",
      "rule": "Only the order owner (the user who placed the order) or an authorized operator may cancel an order. No other user may cancel someone else's order.",
      "invariant": true,
      "invariant_justification": "Allowing unauthorized cancellation would be a fundamental authorization violation — one customer could disrupt another's shipment. This is a data integrity and trust invariant.",
      "testable_assertion": "Given user A's order, when user B (non-admin, non-owner) attempts to cancel it, then the system MUST reject the request with an authorization error."
    },
    {
      "id": "BR-3",
      "rule": "A cancelled order MUST NOT progress to any subsequent fulfillment status. Cancelled is a terminal state.",
      "invariant": true,
      "invariant_justification": "If a cancelled order could transition to 'in_transit' or 'delivered', the system state is corrupt. Downstream systems (billing, tracking, driver dispatch) would operate on contradictory data.",
      "testable_assertion": "Given a cancelled order, when any status-advancing event is received (assign, pickup, deliver), then the system MUST reject the transition and the order MUST remain in cancelled status."
    },
    {
      "id": "BR-4",
      "rule": "When an order is cancelled, a refund must be initiated. The refund amount depends on the order status at cancellation time: full refund if status is 'placed' or 'confirmed'; refund minus cancellation fee if status is 'assigned' (driver already committed resources).",
      "invariant": false,
      "invariant_justification": "The refund policy and cancellation fee structure are business decisions that can be changed by product/finance leadership without corrupting system integrity.",
      "testable_assertion": "Given an order cancelled at status 'placed', when refund is processed, then the refund amount MUST equal the full order amount. Given an order cancelled at status 'assigned', the refund amount MUST equal (order amount - cancellation fee)."
    },
    {
      "id": "BR-5",
      "rule": "When an order in 'assigned' status is cancelled, the assigned driver/courier MUST be notified of the cancellation so they do not attempt pickup.",
      "invariant": true,
      "invariant_justification": "Failure to notify the driver results in wasted physical trips, fuel costs, and eroded driver trust. More critically, the driver may arrive and take possession of goods for a cancelled order, creating a custody discrepancy — a state integrity issue.",
      "testable_assertion": "Given an assigned order that is cancelled, then a cancellation notification event MUST be emitted to the assigned driver within the system's notification SLA."
    },
    {
      "id": "BR-6",
      "rule": "Every cancellation MUST record an audit trail entry: who cancelled, when, from which status, and the reason (if provided).",
      "invariant": true,
      "invariant_justification": "Cancellation audit is required for dispute resolution, fraud detection, and operational reporting. Without it, there is no way to investigate or reconcile order history — the data record is incomplete.",
      "testable_assertion": "Given a successful cancellation, then an audit record MUST exist containing: order_id, initiator_id, timestamp, previous_status, and cancellation_reason."
    },
    {
      "id": "BR-7",
      "rule": "An order that is already cancelled cannot be cancelled again. Cancellation is idempotent — repeated requests should not fail loudly but must not create duplicate refunds or duplicate audit entries.",
      "invariant": true,
      "invariant_justification": "Double-cancellation leading to double-refund is a financial integrity violation. The system state must be consistent regardless of how many times cancellation is requested.",
      "testable_assertion": "Given an already-cancelled order, when a second cancellation request is submitted, then the system MUST return success (idempotent) and MUST NOT create a second refund or a second audit entry."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order in 'placed' status owned by the requesting user",
      "when": "The user submits a cancellation request",
      "then": "The order status transitions to 'cancelled', a full refund is initiated, and an audit trail entry is recorded"
    },
    {
      "id": "AC-2",
      "given": "An order in 'confirmed' status owned by the requesting user",
      "when": "The user submits a cancellation request",
      "then": "The order status transitions to 'cancelled', a full refund is initiated, and an audit trail entry is recorded"
    },
    {
      "id": "AC-3",
      "given": "An order in 'assigned' status owned by the requesting user",
      "when": "The user submits a cancellation request",
      "then": "The order status transitions to 'cancelled', a partial refund (order amount minus cancellation fee) is initiated, the assigned driver is notified, and an audit trail entry is recorded"
    },
    {
      "id": "AC-4",
      "given": "An order in 'picked_up' status",
      "when": "The user submits a cancellation request",
      "then": "The request is rejected with an error message stating 'Order cannot be cancelled after pickup — please use the returns process'"
    },
    {
      "id": "AC-5",
      "given": "An order in 'in_transit' status",
      "when": "The user submits a cancellation request",
      "then": "The request is rejected with an error message directing the user to the returns or dispute flow"
    },
    {
      "id": "AC-6",
      "given": "An order in 'delivered' status",
      "when": "The user submits a cancellation request",
      "then": "The request is rejected with an error message directing the user to the returns or dispute flow"
    },
    {
      "id": "AC-7",
      "given": "An order owned by user A",
      "when": "User B (non-owner, non-admin) submits a cancellation request for that order",
      "then": "The request is rejected with an authorization error and no state change occurs"
    },
    {
      "id": "AC-8",
      "given": "An order that is already in 'cancelled' status",
      "when": "The user submits another cancellation request",
      "then": "The system returns a success response (idempotent), no duplicate refund is created, and no duplicate audit entry is written"
    },
    {
      "id": "AC-9",
      "given": "An order in 'cancelled' status",
      "when": "A downstream system attempts to advance the order to 'in_transit' or 'delivered'",
      "then": "The transition is rejected and the order remains in 'cancelled' status"
    },
    {
      "id": "AC-10",
      "given": "A successful cancellation of any order",
      "when": "The audit log is queried for that order",
      "then": "An entry exists with order_id, initiator_id, timestamp, previous_status, and cancellation_reason"
    }
  ],

  "edge_cases": [
    {
      "scenario": "User cancels an order at the exact moment a driver accepts assignment (race condition between 'confirmed' → 'assigned' and cancellation)",
      "expected_behavior": "The system must use optimistic locking or equivalent concurrency control on order status. Exactly one operation wins. If cancellation wins, the driver assignment is rolled back and the driver is notified. If assignment wins first, cancellation proceeds under 'assigned' rules (partial refund, driver notification)."
    },
    {
      "scenario": "Payment gateway is unavailable when refund is triggered during cancellation",
      "expected_behavior": "The order MUST still transition to 'cancelled' (cancellation and refund are separate concerns). The refund must be queued for retry. The user should be informed that cancellation succeeded but refund is pending. The system must not leave the order in a non-cancelled state because the refund failed."
    },
    {
      "scenario": "User submits cancellation with no reason provided",
      "expected_behavior": "Cancellation proceeds. The reason field in the audit trail is recorded as null/empty. Reason should be optional — requiring it would block legitimate cancellations."
    },
    {
      "scenario": "Admin/operator cancels an order on behalf of a user (e.g., fraud detected)",
      "expected_behavior": "Cancellation is permitted. The audit trail must record the operator as the initiator (not the customer). The refund policy may differ for operator-initiated cancellations (e.g., no refund for fraud). This is a separate policy path."
    },
    {
      "scenario": "Bulk cancellation — user or operator attempts to cancel many orders simultaneously",
      "expected_behavior": "Each order is evaluated independently against cancellation rules. Some may succeed and others may fail (e.g., mixed statuses). The response must clearly report per-order outcomes. Partial success is valid — it must not be all-or-nothing."
    },
    {
      "scenario": "Order has already been invoiced or billed to a third party before cancellation",
      "expected_behavior": "Cancellation proceeds but must trigger a credit note or invoice reversal in the billing system. The cancellation must not leave orphaned invoices in accounts receivable."
    },
    {
      "scenario": "Network timeout — user submits cancellation, gets a timeout, and retries",
      "expected_behavior": "Idempotency ensures the second request succeeds without side effects. The user sees a confirmation. No double refund, no double audit entry."
    },
    {
      "scenario": "Order with multiple parcels/legs — user wants to cancel only part of the order",
      "expected_behavior": "This spec ('cancel their order') implies full-order cancellation only. Partial cancellation (single parcel/leg) is a distinct feature requiring its own rules. If attempted, the system should reject with guidance to cancel the full order or contact support."
    }
  ],

  "business_impact": {
    "financial": "Direct revenue reduction from refunds. Cancellation fees on 'assigned' orders partially offset driver allocation costs. Failure to implement idempotency risks double-refunds — a direct financial leak. Proper cancellation reduces costly failed deliveries and driver deadheading.",
    "operational": "Reduces wasted driver trips when orders are cancelled early. Requires integration with payment/refund systems, driver notification systems, and audit infrastructure. Cancellation rate becomes a key operational metric for demand forecasting and driver utilization planning.",
    "user": "Cancellation capability is table-stakes for user trust. Users who cannot cancel will dispute charges or churn. Clear feedback on cancellation eligibility (which statuses allow it) reduces support tickets. Transparent refund policies reduce friction.",
    "risk": "Primary risks: (1) double-refund from non-idempotent implementation, (2) race conditions at status boundaries causing inconsistent state, (3) driver not notified leading to wasted trips and custody issues, (4) audit gaps preventing fraud detection. All are mitigated by the business rules defined above.",
    "stakeholders_affected": [
      { "group": "Customers (shippers/senders)", "impact": "Gain ability to cancel and receive refunds. Improved trust and control over their orders." },
      { "group": "Drivers/Couriers", "impact": "Must receive timely cancellation notifications to avoid wasted trips. Poor notification erodes driver trust and retention." },
      { "group": "Finance/Billing", "impact": "Must handle refund processing, cancellation fee accounting, and credit notes. New reconciliation requirements." },
      { "group": "Customer Support", "impact": "Reduced inbound volume for manual cancellations. Need visibility into cancellation audit trail for dispute resolution." },
      { "group": "Operations/Dispatch", "impact": "Route optimization must account for cancelled orders. Driver reassignment logic triggered by cancellation." },
      { "group": "Product/Analytics", "impact": "Cancellation rate, cancellation-by-status distribution, and time-to-cancel become key product health metrics." }
    ]
  },

  "confidence": {
    "level": 40,
    "reasoning": "The spec is a single sentence with no detail on cancellation policy, refund rules, fee structures, eligible statuses, authorization model, or partial-cancellation scope. Every business rule above is inferred from standard logistics domain knowledge, not from an actual specification. Key unknowns: exact cancellable statuses, refund percentages, cancellation fee amounts, whether partial order cancellation is needed, SLA for driver notification, and whether operator-initiated cancellations follow different rules. This analysis provides a reasonable default but any of these rules could be wrong for this specific business.",
    "high_confidence_areas": [
      "Cancelled must be a terminal state (BR-3) — universal invariant",
      "Authorization required — only owner or admin can cancel (BR-2)",
      "Audit trail is mandatory for any state-destroying operation (BR-6)",
      "Idempotency on cancellation to prevent double-refund (BR-7)",
      "Physical pickup is the hard boundary for cancellation eligibility (BR-1)"
    ],
    "low_confidence_areas": [
      "Exact set of cancellable statuses — could vary by business model",
      "Refund policy and cancellation fee structure — entirely business-specific",
      "Whether partial order cancellation is in scope",
      "Driver notification SLA and mechanism",
      "Operator-initiated cancellation policies (fraud, etc.)"
    ],
    "assumptions": [
      "Standard courier order lifecycle: placed → confirmed → assigned → picked_up → in_transit → delivered",
      "Cancellation means full-order cancellation, not partial",
      "Payment has been collected at order placement (pre-paid model)",
      "A cancellation fee exists for assigned-status cancellations",
      "Driver notification is a system responsibility, not manual"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order statuses are cancellable. The boundary between 'cancellable' and 'non-cancellable' has major business and financial implications. Is cancellation allowed after driver assignment? After pickup? The analysis assumes pickup is the hard boundary, but this must be confirmed.",
      "affected_stakeholders": ["Customers", "Drivers", "Finance"],
      "options": [
        "A: Cancel only in 'placed' and 'confirmed' (before driver assignment)",
        "B: Cancel up to and including 'assigned' (before physical pickup) — assumed in this analysis",
        "C: Cancel at any point before delivery (requires return-to-sender logistics)"
      ],
      "recommendation": "Option B — 'assigned' is the last clean cancellation point before physical custody transfer. Recommended as default, but PM must confirm."
    },
    {
      "type": "ambiguity",
      "description": "Refund policy is unspecified. Should cancellation always result in a full refund? Is there a cancellation fee? Does fee vary by status? This directly impacts revenue and customer satisfaction.",
      "affected_stakeholders": ["Customers", "Finance"],
      "options": [
        "A: Full refund regardless of status",
        "B: Full refund before assignment, partial refund after assignment (assumed)",
        "C: No refund after confirmation"
      ],
      "recommendation": "Option B — balances customer trust with cost recovery for committed resources. PM and Finance must confirm fee structure."
    },
    {
      "type": "missing_context",
      "description": "No information on whether partial order cancellation (cancelling one parcel or leg of a multi-item order) is required. This is a fundamentally different feature with different invariants.",
      "affected_stakeholders": ["Customers", "Product", "Engineering"],
      "options": [
        "A: Full order cancellation only (assumed)",
        "B: Support partial cancellation with per-item refund logic"
      ],
      "recommendation": "Option A for initial release. Partial cancellation should be a separate, explicitly scoped feature."
    }
  ],

  "rejection_reasons": []
}

